import React, { useState, useEffect } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshMovements, refreshProducts, updateProductQuantity }) => {
    const [products, setProducts] = useState([]);
    const [movement, setMovement] = useState({
        produto: '',
        tipo_movimentacao: 'entrada',
        quantidade: '',
        motivo: ''
    });

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
                setProducts(response.data);
                console.log("Produtos carregados:", response.data); // Log dos produtos carregados
            } catch (error) {
                console.error("Erro ao buscar produtos:", error);
            }
        };

        fetchProducts();
    }, []);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setMovement({ ...movement, [name]: value });
        console.log(`Campo alterado: ${name} = ${value}`); // Log do campo alterado
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const quantidade = parseInt(movement.quantidade, 10);
    
            if (isEditingMovement) {
                // Se estiver editando, faça um PUT
                await axios.put(`http://127.0.0.1:8000/api/movimentacoes/${currentMovementId}/`, {
                    produto: movement.produto,
                    tipo_movimentacao: movement.tipo_movimentacao,
                    quantidade: quantidade,
                    motivo: movement.motivo
                });
    
                console.log("Movimentação atualizada:", movement);
            } else {
                // Se não, faça um POST
                await axios.post('http://127.0.0.1:8000/api/movimentacoes/', {
                    produto: movement.produto,
                    tipo_movimentacao: movement.tipo_movimentacao,
                    quantidade: quantidade,
                    motivo: movement.motivo
                });
    
                console.log("Movimentação registrada:", movement);
            }
    
            // Atualiza a quantidade do produto após o registro da movimentação
            await updateProductQuantity(movement.produto, movement.tipo_movimentacao, quantidade);
    
            // Atualiza a lista de movimentações e produtos
            await fetchMovements(); // Refresh the movements
            await fetchProducts(); // Refresh the products
    
            // Limpa o formulário de movimentação
            setMovement({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });
            setIsEditingMovement(false); // Reseta o modo de edição
            setCurrentMovementId(null); // Reseta o ID da movimentação
        } catch (error) {
            console.error("Erro ao registrar movimentação:", error);
        }
    };
    
    

    return (
        <div>
            <form onSubmit={handleSubmit}>
                <select name="produto" value={movement.produto} onChange={handleChange} required>
                    <option value="">Selecione um Produto</option>
                    {products.map((product) => (
                        <option key={product.id} value={product.id}>
                            {product.nome}
                        </option>
                    ))}
                </select>

                <select name="tipo_movimentacao" value={movement.tipo_movimentacao} onChange={handleChange}>
                    <option value="entrada">Entrada</option>
                    <option value="saida">Saída</option>
                </select>

                <input
                    type="number"
                    name="quantidade"
                    value={movement.quantidade}
                    onChange={handleChange}
                    placeholder="Quantidade"
                    required
                />
                <input
                    type="text"
                    name="motivo"
                    value={movement.motivo}
                    onChange={handleChange}
                    placeholder="Motivo"
                />

                <button type="submit">Registrar</button>
            </form>
        </div>
    );
};

export default StockMovementForm;
